// ── Parse Entry Point ──────────────────────────────────────────────────────
// simple:false -> n8n provides email.subject, email.from, email.to, email.text
// email.from and email.to are nodemailer objects: {value:[{address,name}], text}
const email = $input.first().json;

const subject = email.subject || '';

// ── helpers: handle both string and nodemailer object format ───────────────
function extractAddr(field) {
  if (!field) return '';
  if (typeof field === 'string') {
    const m = field.match(/<([^>]+)>/);
    return (m ? m[1] : field).trim();
  }
  // nodemailer object: {value:[{address,name}], text}
  if (field.value && field.value[0] && field.value[0].address) return field.value[0].address.trim();
  if (field.text) {
    const m = field.text.match(/<([^>]+)>/);
    return (m ? m[1] : field.text).trim();
  }
  return String(field).trim();
}
function extractName(field) {
  if (!field) return '';
  if (typeof field === 'string') {
    const m = field.match(/^([^<]+)</);
    return m ? m[1].trim() : '';
  }
  if (field.value && field.value[0] && field.value[0].name) return field.value[0].name.trim();
  if (field.text) {
    const m = field.text.match(/^([^<]+)</);
    return m ? m[1].trim() : '';
  }
  return '';
}

const SCOTT    = ['scott.metcalf@people.ai', 'metcalf.scott@gmail.com'];
const PERSONAL = ['gmail.com','google.com','googlemail.com','icloud.com',
                  'yahoo.com','hotmail.com','outlook.com','live.com'];

const fromEmail = extractAddr(email.from);
const fromName  = extractName(email.from);
const toEmail   = extractAddr(email.to).toLowerCase();

// Body is decoded by n8n with simple:false
function cleanHtml(h) {
  if (!h || typeof h !== 'string') return '';
  return h.replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')
    .replace(/<br\s*\/?>/gi,'\n').replace(/<\/(p|div)>/gi,'\n').replace(/<[^>]+>/g,'')
    .replace(/\n{3,}/g,'\n\n').trim();
}
const body = email.text || cleanHtml(email.textAsHtml || email.html) || email.snippet || '';

const isFromScott   = SCOTT.some(e => fromEmail.toLowerCase() === e.toLowerCase());
// Primary: Scott emailing his own +assistant alias = unambiguous self-forward
const isSelfForward = isFromScott && toEmail.includes('+assistant@');
// Fallback: subject/body patterns for edge cases
const isFwdSubject  = /^fw[d]?\s*:/i.test(subject);
const isFwdBody     = /-{4,}\s*forwarded\s+message|begin\s+forwarded\s+message/i.test(body);
const isForwarded   = isSelfForward || (isFromScott && (isFwdSubject || isFwdBody));

let senderEmail = fromEmail, senderName = fromName;
let senderDomain = (fromEmail.split('@')[1] || '').toLowerCase();
let originalMessageId = null, originalSubject = subject, originalBody = body;
let originalSenderEmail = '', ccRecipients = '', originalCcLine = '';

if (isForwarded) {
  const fwdIdx = body.search(/-{4,}\s*forwarded\s+message|begin\s+forwarded\s+message/i);
  const fwdBlock = fwdIdx >= 0 ? body.substring(fwdIdx) : body;

  // From: "Name" <email> — stop at newline
  const fm = fwdBlock.match(/From:\s*(?:"?([^"<\n\r]+?)"?\s*)?<([^>\n\r]+)>/i);
  if (fm) {
    senderName          = (fm[1] || '').trim();
    senderEmail         = fm[2].trim();
    senderDomain        = (senderEmail.split('@')[1] || '').toLowerCase();
    originalSenderEmail = senderEmail;
  }

  // Message-ID — stop at newline
  const mm = fwdBlock.match(/Message-ID:\s*<([^>\n\r]+)>/i);
  if (mm) originalMessageId = mm[1].trim();

  // Subject — stop at end-of-line only (no consuming next header fields)
  const sm = fwdBlock.match(/Subject:\s*([^\n\r]+)/i);
  if (sm) originalSubject = sm[1].trim().replace(/^fw[d]?\s*:/i, '').trim();

  // Body = everything after the blank-line separator in the forwarded block
  const bodyStart = fwdBlock.indexOf('\n\n');
  originalBody = (bodyStart >= 0 ? fwdBlock.substring(bodyStart) : fwdBlock).trim();

  // Parse all participants from To: and Cc: lines in the forwarded block
  // Filter out Scott's own addresses — the remaining are CC recipients in the reply
  function parseAddressList(line) {
    if (!line) return [];
    const addrs = [];
    const re = /(?:"?([^"<,\n\r]*?)"?\s*)?<([^>\n\r]+)>|([\w._%+\-]+@[\w.\-]+\.[a-zA-Z]{2,})/g;
    let m;
    while ((m = re.exec(line)) !== null) {
      const email = (m[2] || m[3] || '').trim().toLowerCase();
      const name  = (m[1] || '').trim();
      if (email) addrs.push({ name, email });
    }
    return addrs;
  }
  // Headers may be indented with spaces; handle both Cc: and CC:
  const fwdToLine = (fwdBlock.match(/^\s*To:\s*([^\n\r]+)/im) || [])[1] || '';
  const fwdCcLine = (fwdBlock.match(/^\s*CC?:\s*([^\n\r]+)/im) || [])[1] || '';
  originalCcLine = fwdCcLine;
  const fwdAllParticipants = [...parseAddressList(fwdToLine), ...parseAddressList(fwdCcLine)];
  ccRecipients = fwdAllParticipants
    .filter(a => !SCOTT.some(s => a.email === s.toLowerCase()))
    .filter(a => a.email !== senderEmail.toLowerCase())
    .map(a => a.name ? a.name + ' <' + a.email + '>' : a.email)
    .join(', ');
}

const isAssistantAlias = toEmail.includes('+assistant@');
const isCustomer = !PERSONAL.includes(senderDomain);

// forwardedMessageId = Gmail message ID of the +assistant copy (to archive from INBOX)
let forwardedMessageId = null, forwardedThreadId = null, originalThreadId = email.threadId;
if (isForwarded) {
  forwardedMessageId = email.id;       // the +assistant email's own Gmail message ID
  forwardedThreadId  = email.threadId;
  originalThreadId   = null;
}

return [{
  json: {
    ...email,
    subject: originalSubject || subject,
    isForwarded,
    isAssistantAlias,
    isCustomer,
    senderEmail,
    senderName,
    senderDomain,
    originalSenderEmail,
    originalMessageId,
    originalSubject,
    originalBody,
    ccRecipients,
    originalCcLine,
    forwardedMessageId,
    forwardedThreadId,
    originalThreadId,
  }
}];

