  const d = new Date(emailCtx.date || Number(emailCtx.internalDate));
  if (!isNaN(d)) dateStr = d.toLocaleString('en-US', {
    weekday:'short', year:'numeric', month:'short',
    day:'numeric', hour:'2-digit', minute:'2-digit'
  });
} catch(e) {}

const ccLine = emailCtx.originalCcLine ? '\nCC: ' + emailCtx.originalCcLine : '';
output.message += sig
  + '\n\n------- Original Message -------'
  + '\nFrom: ' + orig
  + (dateStr ? '\nDate: ' + dateStr : '')
  + '\nSubject: ' + (emailCtx.originalSubject || emailCtx.subject || '')
  + ccLine
  + '\n\n' + (emailCtx.originalBody || emailCtx.text || '');

// Pass email context through so Save Draft can read it
return items.map(i => ({ json: { ...emailCtx, ...i.json, output } }));

// ── Email Routing Policy ─────────────────────────────────────────────────
// Edit these lists to control automated draft behaviour per sender.

// Spam: matched senders are silently marked read — no draft, no Slack alert
const SPAM_PATTERNS = [
  /no.?reply/i, /noreply/i, /donotreply/i, /do-not-reply/i,
  /mailer-daemon/i, /postmaster/i, /bounce\+/i, /newsletter/i,
  /notifications?@/i, /alerts?@/i, /\+caf_/i,
];

// Blocked domains: organisations that never get automated drafts
const BLOCKED_DOMAINS = [
  'google.com',
  'linkedin.com',
  'salesforce.com',
  'github.com',
  'slack.com',
  'zoom.us',
];

// Blocked addresses: individual senders that never get automated drafts
const BLOCKED_ADDRESSES = [
  // 'specific@company.com',
];

// Auto-send domains: drafts sent automatically after delay if unedited
const AUTO_SEND_DOMAINS = [
  // 'trustedpartner.com',
];

// Auto-send addresses: specific senders whose drafts are auto-sent
const AUTO_SEND_ADDRESSES = [
  // 'colleague@company.com',
];

// Hours to wait before auto-sending (only applies to auto-send tier)
const AUTO_SEND_DELAY_HOURS = 2;

// ── Classify ─────────────────────────────────────────────────────────────
const email       = $input.first().json;
const fromEmail   = (email.senderEmail  || '').toLowerCase();
const fromDomain  = (email.senderDomain || '').toLowerCase();
const labelIds    = email.labelIds || [];

const isGmailSpam   = labelIds.includes('SPAM');
const isPatternSpam = SPAM_PATTERNS.some(p => p.test(fromEmail));
const isSpam        = isGmailSpam || isPatternSpam;

const isBlockedDomain  = BLOCKED_DOMAINS.some(d => fromDomain === d || fromDomain.endsWith('.' + d));
const isBlockedAddress = BLOCKED_ADDRESSES.map(a => a.toLowerCase()).includes(fromEmail);
const isBlocked        = isBlockedDomain || isBlockedAddress;

const isAutoSendDomain  = AUTO_SEND_DOMAINS.some(d => fromDomain === d || fromDomain.endsWith('.' + d));
const isAutoSendAddress = AUTO_SEND_ADDRESSES.map(a => a.toLowerCase()).includes(fromEmail);
const isAutoSend        = isAutoSendDomain || isAutoSendAddress;

let route;
if      (isSpam)    route = 'spam';
else if (isBlocked) route = 'blocked';
else                route = 'draft';

return [{ json: { ...email, route, isSpam, isBlocked, isAutoSend, autoSendDelayHours: AUTO_SEND_DELAY_HOURS } }];

